What does this program print to **stdout** (not stderr)?

```cpp
#include <iostream>

int addThree(int x) {
    std::cerr << "called\n";
    return x + 3;
}

int main() {
    int v = addThree(7);
    std::cout << v << "\n";
    return 0;
}
```

What does this program print to **stdout**?

```cpp
#include <iostream>

int triple(int x) {
    std::cerr << "[trace] triple x=" << x << "\n";
    return x * 3;
}

int main() {
    std::cout << triple(4) << "\n";
    std::cout << triple(0) << "\n";
    return 0;
}
```
